var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"그림자 토벌 확인. 사냥 종료.","JPN":"シャドウ討伐確認。狩りは終了です。","ENG":"Shadow exterminated. The hunt has ended.","TWN":"暗影討伐完畢，狩獵結束。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"함선에 복귀하시는대로 현실 부상을 개시하겠습니다.","JPN":"艦船に復帰されましたら、すぐに現実への浮上を開始します。","ENG":"Reemergence to the Normalside will commence as soon as you return to the ship.","TWN":"在你返回艦船後，本艦將立即向現世躍出。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"추격전을 다섯 번이나 치르게 만들다니. 끈질긴 녀석이군.","JPN":"5回も追撃戦をやらせるとは、しつこい奴だ。","ENG":"Making us chase after it five times. Persistent, much?","TWN":"竟然讓我們追了五次，真是個頑固的傢伙。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"시렌 전대가 아니었다면 이번에도 놓치고 말았겠지.","JPN":"シレン戦隊の協力がなければ、今回も見逃していただろう。","ENG":"If it weren't for Sirin Division, we would've let it get away again.","TWN":"如果不是賽蓮小隊，這次也會錯過的吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"고생 많았다, 율리아.","JPN":"ご苦労だった、ユリア。","ENG":"Great work, Yulia.","TWN":"辛苦了，茱莉亞。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그러게요… 간신히 잡았어요.","JPN":"そうですね……なんとか捕まえました。","ENG":"Yes... We barely caught it.","TWN":"是啊……好不容易才逮到的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"제가 저희 대원들처럼 카운터였다면, 고생을 좀 덜었을 텐데 말이죠.","JPN":"隊員たちのように私もカウンターだったら……もう少し楽にできたんでしょうけど。","ENG":"If I was also a Counter like the rest of our members, maybe it would've been easier.","TWN":"如果我像我們的隊員們一樣是制裁者的話，可能就不會這麼辛苦了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"힐데 씨.","JPN":"ヒルデさん。","ENG":"Miss Hilde?","TWN":"希爾德。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"왜 그러지?","JPN":"なんだ？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이 그림자가 이런 특이한 검을 갖고 있던데… 혹시 알아보시겠어요?","JPN":"このシャドウ、変わった剣を持っていましたが……ヒルデさんはこれが何かわかりますか？","ENG":"This Shadow had this strange-looking sword... Do you recognize it?","TWN":"這個暗影拿著這樣一把特別的劍……你認得它嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"이건…? 울브즈베인?","JPN":"これは……？　ウルブズベイン？","ENG":"That's...? Wolvesbane?","TWN":"這是……？狼之災禍？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아니, 그럴 리 없지. 이 검이 두 자루가 존재할 리는 없으니까.","JPN":"いや、まさか……この剣が2本も存在するはずがない。","ENG":"No, it can't be. There is no way two of these swords exist.","TWN":"不，不可能。這把劍不可能有兩把。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그런가요?","JPN":"そうですか？","ENG":"Really?","TWN":"是嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"만약… 이 그림자가… 우리가 알던 그 늑대일 수도 있지 않겠어요?","JPN":"もしかすると……このシャドウが、私たちの知っているあのオオカミの可能性もあるのでは？","ENG":"Then... could this Shadow... be the Wolf we knew?","TWN":"如果說……這個暗影……就是我們認識的那隻狼，這可能嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"늑대가 둘일 수는 없다.","JPN":"オオカミが2人存在する可能性はない。","ENG":"There can't be two Wolves.","TWN":"狼不可能有兩個。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"왜 그런 터무니없는 얘길 하는지 모르겠군.","JPN":"なぜそんな突拍子もないことを言うんだ？","ENG":"I don't see why you are talking such nonsense.","TWN":"真搞不懂你為什麼會說出這麼荒謬的話。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…역시 그렇죠?","JPN":"……やはり、そうですよね。","ENG":"…You're right.","TWN":"……你說的沒錯。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"못 들은 걸로 해주세요.","JPN":"今のは聞かなかったことにしてください。","ENG":"Please, just ignore me.","TWN":"請當作沒聽到吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이면세계에 오래 머물렀더니 머리가 이상해졌나 봐요.","JPN":"裏世界に長居したせいで、頭がどうにかなったようです。","ENG":"Maybe my head was in the clouds after being in the Counterside for too long.","TWN":"在異界待久了，腦子好像有點不正常了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"어떻습니까?","JPN":"どうですか？","ENG":"So?","TWN":"如何？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"진실을 알고서 이면의 것들을 마주하게 된 소감은?","JPN":"真実を知って、裏世界の存在に向き合った感想は？","ENG":"How does it feel to know the truth and see what is on the other side?","TWN":"知道真相後，面對異界的事物有什麼感想？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…네. 이제야 알겠어요.","JPN":"……はい。やっとわかりました。","ENG":"...Yes. I understand now.","TWN":"……是的。現在我明白了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 수많은 그림자들에게서 느낀 기시감은… 착각이 아니었군요.","JPN":"あの数えきれないシャドウたちから感じた既視感は……私の勘違いではなかった。","ENG":"The sense of deja vu I felt from those countless Shadows... I wasn't mistaken.","TWN":"從那些無數的暗影中感受到的似曾相識感……果然不是錯覺。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이런 식으로… 옛 세계에 남겨진 전우들을 몇 번씩이고 제 손으로 죽이고 있었던 거네요.","JPN":"こうして私は……旧世界に残された戦友たちを、何度も手にかけてきたのですね。","ENG":"I've been killing the comrades left behind in the old world again and again, with my own hands...","TWN":"就這樣……我一次又一次地親手殺死了留在舊世界的戰友們。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"왼쪽 팔이 없었던 그 그림자는… 부전대장 타티아나.","JPN":"左腕がなかったあのシャドウは……副戦隊長のタテイアナ。","ENG":"The Shadow that had no left arm... That was Deputy Commander Tatiana.","TWN":"缺了左臂的那個暗影是……副戰隊長塔蒂亞娜。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"가시로 뒤덮인 목 없는 그림자는… 말더듬이 신병 나탈리아.","JPN":"いばらに覆われた首なしのシャドウは……新兵のナタリア。","ENG":"The headless Shadow covered in thorns... That was the stuttering recruit, Natalia.","TWN":"被荊棘覆蓋的無頭暗影……結巴的新兵那塔利亞。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그리고 익숙한 대검을 휘두르던 외눈의 그림자는…","JPN":"そして、見慣れた大剣を振るっていた隻眼のシャドウは……","ENG":"And the one-eyed Shadow that wielded a familiar greatsword must have been...","TWN":"而揮舞著那把熟悉的大劍的獨眼暗影則是……"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"시렌 전대를 창설했던 제 아버지… 펠릭스였겠죠.","JPN":"シレン戦隊の創設者、私の父親……フェリックスだったのでしょう。","ENG":"...my father and founder of the Sirin Division... Felix.","TWN":"創立賽蓮小隊的我的父親……緋利克斯。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이제 말해줘요, 삼하인.","JPN":"教えてください、サウィン。","ENG":"Now, tell me, Samhain.","TWN":"現在告訴我吧，薩溫。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신이 나에게서 원했던 건… 고작 내 영혼 하나가 아닌 거죠?","JPN":"あなたが私に求めていたのは……私の魂だけではない、そうでしょう？","ENG":"What you wanted from me... it wasn't just my soul, was it?","TWN":"你從我這裡想要的……不僅僅是我的靈魂吧？"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"제가 원하는 건 당신이 모든 기억을 간직한 채, 계속해서 미래로 나아가는 겁니다.","JPN":"私の望みは、あなたがすべての記憶を持ったまま、更なる未来へ進むことです。","ENG":"What I want is for you to keep moving forward with all your memories.","TWN":"我希望你能保留所有的記憶，繼續向未來前進。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 당신의 영혼을 차표 삼아 그 운명에 오른 승객일 뿐이죠.","JPN":"私はあなたの魂をチケットの代わりにして、運命に乗り込んだ乗客にすぎない。","ENG":"I am merely a passenger who boarded on your fate using your soul as a ticket.","TWN":"我只是以你的靈魂為車票，登上命運之旅的乘客而已。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 선로의 끝에서… 우린 무엇을 마주하게 될까요?","JPN":"その線路の果てで……私たちは何に向き合うのでしょう。","ENG":"And what will we face... at the end of the tracks?","TWN":"那在那條軌道的盡頭……我們會遇見什麼呢？"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"대적자, 마왕, 늑대… 그 모든 것을 만들어낸 <color=#ffd34c>원죄</color>","JPN":"敵対者、魔王、オオカミ……そのすべてを生み出した<color=#ffd34c>原罪</color>。","ENG":"The Antagonist, the Demon Lord, the Wolf... and the <color=#ffd34c>original sin</color> that created it all.","TWN":"敵對者、魔王、狼……這一切都是由<color=#ffd34c>原罪</color>所創造的。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"전 수많은 이들과 계약하며 오랜 여행을 거쳐온 끝에, 그 원죄의 이름을 알아냈답니다.","JPN":"沢山の人と契約し、長い間旅を続け……私はその原罪の名がわかりました。","ENG":"After having traveled a long journey and making contracts with countless people, I have discovered the name of the original sin.","TWN":"我與無數人簽訂了契約，經過漫長的旅程，終於知道了那個原罪的名字。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 이름은… 탐미엘.","JPN":"その名は……タミエル。","ENG":"That name is... Tammiel.","TWN":"那個名字是……塔米爾。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그녀 또한 여느 마왕들과 마찬가지로 사도를 부리죠.","JPN":"そして彼女もまた、魔王と同じく使徒を従わせている。","ENG":"And she, too, like many other Demon Lords, has Apostles.","TWN":"而且她也像其他魔王一樣擁有使徒。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"정말… <color=#ffd34c>그자</color>가 탐미엘의 사도라면…","JPN":"本当に……<color=#ffd34c>あの者</color>がタミエルの使徒なら……","ENG":"If... <color=#ffd34c>she</color> is truly Tammiel's Apostle...","TWN":"如果……<color=#ffd34c>那傢伙</color>真的是塔米爾的使徒……"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그걸 증명하는 방법은 뭐죠?","JPN":"どうやってそれを証明すればいいのです？","ENG":"...how can you prove that?","TWN":"你要怎麼證明呢？"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그들과 함께하다 보면, 머잖아 알게 될 겁니다.","JPN":"彼らと共にすれば……いずれわかるでしょう。","ENG":"Once you are with them, you will soon find out for yourself.","TWN":"和他們在一起的話，不久後你就會明白的。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"세계는 세피로트 나무를 지배하는 마왕 탐미엘에 의해 순환을 거듭하는 것.","JPN":"世界はセフィロトの木を支配する魔王、タミエルによって循環を繰り返す。","ENG":"This world continues its cycle through the Demon Lord Tammiel, the ruler of the Tree of Sefirot.","TWN":"世界在掌控著生命樹的魔王塔米爾的支配下不斷迴圈。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"그 마왕의 사도는 당신처럼 영혼을 팔지 않더라도, 옛 세계의 기억을 온존하는 특별한 존재니까요.","JPN":"魔王の使徒はあなたのように魂を売らずとも、旧世界の記憶を失わない特別な存在ですから。","ENG":"And that Demon Lord's Apostle is a special being who can preserve the memories of the old world, even without selling her soul like you did.","TWN":"那個魔王的使徒不像你一樣，她是即使不用出賣靈魂，也能保留舊世界記憶的特殊存在。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"실망스럽네. 고작 침입자 한 명에게 인질을 내어주다니.","JPN":"君には失望した。たかが侵入者1人に人質を奪われるとは。","ENG":"How disappointing. You let a single intruder take our hostage.","TWN":"真讓人失望啊。居然把人質交給了區區一個入侵者。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…면목 없습니다. 장군님.","JPN":"……面目ありません、将軍。","ENG":"...Forgive me, General.","TWN":"……我很慚愧，將軍。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그녀의 몸속에 있는 폭탄을 왜 사용하지 않고 해제해줬지?","JPN":"なぜ、彼女の体内にある爆弾を解除した？","ENG":"Why did you disarm the bomb inside her instead of detonating it?","TWN":"為什麼不引爆她體內的炸彈，而是解除它？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"적어도 지원군이 올 때까지 시간을 벌 순 있었을 텐데 말이야.","JPN":"せめて支援軍が車で時間を稼ぐこともできたはずだ。","ENG":"You could have at least bought some time until reinforcements arrived.","TWN":"至少那可以拖延時間，直到援軍到來吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그렇게 했다간… 주변 병사들의 목숨도 위험해지는 상황이었습니다.","JPN":"そうすれば……周りの兵士たちも危険に晒すことになります。","ENG":"If I did that... it would have endangered the lives of the troops around me.","TWN":"那樣做的話……周圍士兵的也會變得很危險。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그래서 어쩔 수 없이 그자들에게 협조를…","JPN":"それで、仕方なく彼らに協力を……","ENG":"I had no choice but to cooperate with them...","TWN":"所以才不得不與他們合作……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"후후, 이상한 얘기네.","JPN":"ふふ、おかしな話だな。","ENG":"Fu fuu. How strange.","TWN":"呵呵，真是個奇怪的藉口。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"내가 아는 레노어는 임무를 위해서라면 부하와 자기 목숨도 아끼지 않았는데.","JPN":"私の知っているレノアは、任務のためなら部下はもちろん自分の命も差し出すような人間だった。","ENG":"The Lenore I knew didn't spare her subordinates or even her own life for the sake of the mission.","TWN":"我所知道的蕾諾雅，為了任務連部下和自己的性命會毫不猶豫犧牲。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그런 녀석의 원본이… 왜 이런 겁쟁이 같은 변명을 하는 걸까?","JPN":"そんなやつのオリジナルが……なぜ臆病者のように言い訳をする？","ENG":"But why is her original... giving me such cowardly excuses?","TWN":"那個傢伙的原型……為什麼要找這種膽小的藉口呢？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…모르겠습니다.","JPN":"……わかりません。","ENG":"...I do not know, ma'am.","TWN":"……我不知道。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그냥… 그럴 수가 없었습니다.","JPN":"ただ……そうすることができませんでした。","ENG":"I just... couldn't do it.","TWN":"只是……我做不到。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"넌 그런 실책을 범하고도 도망치지 않고 이곳에 남았지.","JPN":"君はそんな失敗をしたにも関わらずここに残った。","ENG":"Yet, you decided to stay after making that mistake.","TWN":"你犯了那樣的錯誤，卻沒有逃跑，而是留在了這裡。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이런 식으로 임무를 망쳐도, 내가 널 처형하지 않을 거란 확신이 있었기 때문일까?","JPN":"任務に失敗しても私が君を処刑しないという確信があったから？","ENG":"Was it because you were confident that I wouldn't execute you even after ruining the mission like this?","TWN":"你是不是認為即使這樣搞砸任務，我也不會處決你？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그런 확신은 없었습니다. 미래도 보지 못했습니다.","JPN":"そのよな確信はありませんでしたし、そんな未来も見えませんでした。","ENG":"Not at all. I couldn't even see into the future.","TWN":"我沒有那樣的自信，也看不到未來。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그저… 도망치는 게 무의미하단 걸 알고 있을 뿐입니다.","JPN":"ただ……逃げても無駄だということがわかっていただけです。","ENG":"I just... knew that running would be pointless.","TWN":"只是……我知道逃跑是沒有意義的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그래.","JPN":"そう。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"내 실험체들은 모두 암시가 걸려있으니까.","JPN":"私の実験体たちには皆、暗示をかけている。","ENG":"That's because every one of my test subjects is under hypnosis.","TWN":"我的實驗品全都有施加暗號。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마법의 단어</color> 하나면, 내 지시를 따를 수 밖에 없도록 말이야.","JPN":"<color=#ffd34c>魔法の言葉</color>を聞かせることで、私の指示に逆らえなくなるのだ。","ENG":"I just say the <color=#ffd34c>magic word</color>, and you will have no choice but to follow my orders.","TWN":"只要我說出那個<color=#ffd34c>魔法般的詞語</color>，你就只能聽從我的指示了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"레노어, 지금부터 내가 너에게 권총을 한 자루 줄 거야.","JPN":"レノア、今から私は君に拳銃を1丁渡す。","ENG":"Lenore, I'm going to hand you a pistol.","TWN":"蕾諾雅，我現在要給你一把手槍。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이게 뭘 의미하는진 알겠지?","JPN":"これの意味、わかるだろう？","ENG":"Do you understand what that means?","TWN":"你知道這就表示什麼吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…죄송합니다! 장군님!","JPN":"……申し訳ありません、将軍！","ENG":"...Forgive me! General!","TWN":"……對不起，長官！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"기회를 주신다면 다음엔 절대로 실패하지 않겠…!","JPN":"チャンスを与えてくだされば、次は絶対失敗しな……！","ENG":"If you just give me another chance, I won't ever fail–!","TWN":"如果給我機會，下次絕對不會失敗……！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"쉿, 그냥 받아.","JPN":"しーっ。黙って受け取るんだ。","ENG":"Hush, and just take it.","TWN":"噓，拿著就好。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…네.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"네 관자놀이에 총구를 대고, 방아쇠를 당겨.","JPN":"こめかみに銃口を当てて、引き金を引け。","ENG":"Now, place the barrel at your temple and pull the trigger.","TWN":"把槍口對準你的太陽穴，扣動扳機。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"장군님, 제… 제발…","JPN":"将軍、お……お願……","ENG":"General, p-please...","TWN":"將軍，我……求求你……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"레노어.","JPN":"レノア。","ENG":"Lenore.","TWN":"蕾諾雅。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"부탁해?","JPN":"頼んだよ。","ENG":"Please?","TWN":"拜託了？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"윽…?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"呃……？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"헉…","JPN":"はっ……","ENG":"Grgh...","TWN":"呼……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"허억…","JPN":"はあっ……","ENG":"Gah...!","TWN":"呼……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"공포탄이야.","JPN":"空弾だ。","ENG":"It was a blank.","TWN":"是空包彈呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"후훗, 그 반응… 정말로 자기가 죽을 줄 알았나 보네.","JPN":"ふふ、その反応……本当に死ぬと思ったようだな。","ENG":"Fu fuu, that reaction... You must have thought you were really going to die.","TWN":"呵呵，看你的反應……還以為自己真的會死呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"네가 스완만큼 대단한 거짓 연기로 날 속인 거라면, 그것도 인정해줘야겠어.","JPN":"それともスワンほどの演技力で私を騙したのかな？　もしそうなら、それはそれで認めよう。","ENG":"Or if you deceived me with an act as convincing as Swan's, props to you.","TWN":"如果你能像史旺那樣用高超的演技騙過我，那我也得承認你的厲害。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이… 이게…","JPN":"こ……これは……","ENG":"I-I...","TWN":"這……這是……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"무슨 상황인지 잘… 모르겠습니다만…?","JPN":"いったい、どうゆう状況か……理解が……","ENG":"I don't really understand... what's going on...","TWN":"我不太清楚……現在是什麼情況……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"네가 그 인질을 반드시 죽이길 바랐다면, 처음부터 이 마법의 단어를 아낄 필요가 없었겠지.","JPN":"どうしても君にあの人質を殺して欲しかったのなら、最初から魔法の言葉を使えばよかったのだ。","ENG":"If I wanted you to kill that hostage, I would have used this magic word in the first place.","TWN":"如果我真的希望你殺死那個人質，一開始對你使用這個暗號就好。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 여자가 죽고 사는 건 부수적인 문제일 뿐이야.","JPN":"彼女の生死は重要じゃない。","ENG":"Whether she lives or dies is only a small matter.","TWN":"那個女人的生死只是次要問題。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"난 네가 그걸 해낼 수 있는지 보고 싶었거든.","JPN":"私は、君にそれができるかどうかを確かめたかった。","ENG":"I just wanted to see if you could go through with it or not.","TWN":"但我想看看你是否能做到。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"하지만…","JPN":"だが……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아무래도 넌 그 <color=#ffd34c>복제품</color>과는 다른 존재인 모양이네.","JPN":"どうやら君は、あの<color=#ffd34c>コピー品</color>とは別の存在らしい。","ENG":"It seems that you really are different from that <color=#ffd34c>clone</color>.","TWN":"現在看來，你和那個<color=#ffd34c>克隆人</color>是不同的存在呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그렇지?","JPN":"そうだろう？","ENG":"Aren't you?","TWN":"對吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"저는… 잘 모르겠습니다.","JPN":"私は……よくわかりません。","ENG":"I... am not sure.","TWN":"我……不太清楚。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"분명 기억 속의 전… 지난 3년 동안 아버지의 정적들을 제 손으로 처분해왔어요.","JPN":"確かに、記憶の中の私は……この3年間、父の政敵たちを自分の手で始末してきました。","ENG":"In my memories... I dealt with my father's political enemies for the past 3 years.","TWN":"我分明記得記憶裡……在過去的三年，我親手處決了父親的政敵。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"임무를 위해 수많은 아군과 적을 살해했고… 또…","JPN":"任務のためにたくさんの味方と敵を殺して……そして……","ENG":"I've murdered many allies and enemies for the sake of the mission... Also...","TWN":"為了任務殺死了無數的敵人和同伴……還有……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…그걸 즐기던 감각까지 생생하게 느껴집니다.","JPN":"それを楽しいと思った感覚も、鮮明に覚えています。","ENG":"...I remember vividly that I enjoyed it.","TWN":"……甚至能清晰地感受到享受那一刻的感覺。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그런데 전… 도저히 못하겠어요.","JPN":"それなのに……どうしてもできません。","ENG":"But I... can't put myself to do it.","TWN":"但是我……真的做不到。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"명령 때문에 죄 없는 사람을 죽이는 짓은… 할 수 없습니다.","JPN":"いくら命令だからと罪のない人を殺すことは……できません。","ENG":"I won't kill an innocent person... even if it's an order.","TWN":"因為命令而殺害無辜的人……我做不到。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"흐음…","JPN":"ふむ……","ENG":"Hmm...","TWN":"蕾諾雅啊，蕾諾雅……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이래서야 쓸모가 없겠네.","JPN":"これでは、使い物にならないな。","ENG":"Well, you won't be of any use like this.","TWN":"這樣的話你就沒用了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"나가렴.","JPN":"出て行け。","ENG":"Get out.","TWN":"你出去吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…예?","JPN":"……え？","ENG":"...Excuse me?","TWN":"……嗯？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그게… 무슨 말씀이신지…?","JPN":"それは……どういう……？","ENG":"May I ask... what that means...?","TWN":"那是……什麼意思……？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"너 같은 실패작은 북방합의체에 필요 없다는 뜻이야.","JPN":"君のような失敗作は北方合意体に必要ないという意味だ。","ENG":"It means that the Northern Union doesn't need failures like you.","TWN":"像你這樣的失敗品，北方和議會不需要了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"한 시간 뒤, 넌 임무를 거스르고 현장에서 도망친 반역자로 수배될 테니까.","JPN":"1時間後、君は命令に逆らって任務現場から逃げた反逆者として指名手配されるだろう。","ENG":"In an hour, you will be wanted as a traitor for defying the mission and fleeing the scene.","TWN":"一小時後，你將被通緝為違抗任務並從現場逃跑的叛徒。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…진심이신가요?","JPN":"……本気ですか？","ENG":"...Are you serious?","TWN":"……你是認真的嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"네 아버지의 허울 뿐인 명예를 위해 순순히 처형대에 오르겠다면, 여기 남아도 돼.","JPN":"君の父の名誉のために、大人しく処刑台に立つつもりなら残るといい。","ENG":"If you are willing to protect your father's vain honor and kneel before the guillotine, you can decide to stay.","TWN":"如果你願意維護你父親那虛假的榮譽而甘願走上斷頭台，那就留下來吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"하지만, 겁쟁이 답게 도망쳐서 살아남고 싶다면-","JPN":"だが、臆病者らしく逃げて生き延びたければ……","ENG":"But, if you want to flee and live like the coward you are...","TWN":"但是，如果你想像個膽小鬼一樣逃跑活命的話……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"지금 내가 열어둔 문이, 마지막 기회라고 해둘게.","JPN":"さっきあそこのドアを開けておいた。あれが最後のチャンスだ。","ENG":"This door I opened now, is your last chance.","TWN":"現在我願意為你打開的這扇門，就當作是最後的機會吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"반역자를 잡아야 한다! 실험 지역 일대를 봉쇄하고 샅샅이 뒤져!","JPN":"反逆者を捕まえるんだ！　実験地域一帯を封鎖して隅々まで調べろ！","ENG":"Catch the traitor! Block off the testing area and search every corner!","TWN":"必須抓住叛徒！封鎖實驗區域，徹底搜查！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_A","text":{"KOREA":"저 사람… 피칠갑을 하고 있는데, 경찰에 신고해야 하는 거 아니야?","JPN":"あの人……血まみれだけど、警察に通報したほうがいいんじゃない？","ENG":"That person... She's covered in blood. Shouldn't we report her to the police?","TWN":"喂……那個人，渾身是血，不應該報警嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_B","text":{"KOREA":"내버려 둬. 할로윈 코스프레겠지.","JPN":"ほっとけ。ハロウィンのコスプレか何かだろ。","ENG":"Leave her be. I'm sure it's just her Halloween costume.","TWN":"省省吧，這只是萬聖節裝扮。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_A","text":{"KOREA":"아까부터 헌혈차 주변을 기웃대던데… 그것도 컨셉인가?","JPN":"さっきから献血バスの周りをうろうろしてるけど……あれもそういう設定なのかな？","ENG":"She's been snooping around the blood donation van... Is that also just her being in character?","TWN":"可我看她一直在捐血車附近徘徊……這也是設定嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_B","text":{"KOREA":"쉿, 저 톱 장난감이 아닌 거 같아. 괜히 눈 마주치지 말자.","JPN":"しーっ。あのノコギリ、本物な気がする。目を合わせないようにしよう。","ENG":"Quiet. I don't think that saw is a toy. Don't make eye contact with her.","TWN":"噓，那鋸子好像不是玩具。別再看那傢伙了啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으으… 좋은 냄새…","JPN":"うう……いい匂い……","ENG":"Mm... It smells so good…","TWN":"呃呃……好香……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"한 팩만 달라고 하면 분명 신고 당하겠지?","JPN":"1パックだけほしいって言ったら、通報されるかな？","ENG":"I'll get reported if I ask for a pack, right?","TWN":"只喝一包的話，不會被抓的吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…팔 하나 잘라볼까? 응급 환자인 척 쓰러지면 수혈이라도 해주지 않으려나?","JPN":"……腕を切ってみようかな？　緊急患者のふりをして倒れたら、輸血してもらえたりして……","ENG":"...Maybe I should cut off an arm? Won't they give me a blood transfusion if I pretend to be an emergency patient?","TWN":"……要不要砍掉一隻手試試？假裝成急救病人，他們會不會給我輸血呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"감시원들 눈을 피해 무슨 음모를 꾸미나 했더니…","JPN":"監視の目を逃れて何を企んでいるのかと思えば……","ENG":"I was wondering what you were up to avoiding the guards' eyes, but...","TWN":"我還以為你避開守衛的眼睛在策劃什麼陰謀呢……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"대로변에 숨어 자해공갈을 계획하고 있을 줄은 몰랐군요.","JPN":"道端に隠れて自害作戦を立てていたとは心外ですね。","ENG":"I didn't expect you to be hiding on the side of the road, plotting to hurt yourself.","TWN":"沒想到是在路邊想這種詐騙的伎倆。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗… 관리국 깡패…!","JPN":"あっ、管理局のごろつき……！","ENG":"Huh...?! The Administration gangster...!","TWN":"啊……管理局的黑幫……！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 깡패가 아닙니다.","JPN":"私はごろつきではありません。","ENG":"I am not a gangster.","TWN":"我不是黑幫。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"거짓말! 처음 만났을 때부터 날 피냐타처럼 때려 놓고선!","JPN":"嘘！　初めて会った時だって私をピニャータみたに叩き潰したくせに！","ENG":"Liar! You beat me up like a piñata when we first met!","TWN":"騙子！從第一次見面就把我暴打了一頓！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어 소집 회담 때를 말하는 겁니까?","JPN":"シニア召集会談の時の話ですか？","ENG":"Are you talking about the Senior convention meeting?","TWN":"你是說Senior會議的時候嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 당신이 여직원의 목덜미를 노리고 이빨을 드러내기에 제지했을 뿐입니다.","JPN":"私はあなたが牙を剥いて、女性社員の首元を狙おうとしたから阻止しただけです。","ENG":"I only stopped you because you showed your teeth and tried to bite the back of a female employee's neck.","TWN":"我只是阻止了你對女員工的後頸露出獠牙而已。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그때는 이상한 변태라고만 생각했는데… 과거의 사정을 알고 나니 명백한 흡혈 시도였군요.","JPN":"あの時はただの変態だと思いましたが……あれは意図した吸血のための行動だったのですね。","ENG":"At the time, I thought you were just a pervert, but... now that I think back on it, you were trying to suck on her blood.","TWN":"那時候只覺得你是個奇怪的變態……在了解到你過去的情況後，才知道那其實是吸血的企圖。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그, 그땐 마스크를 잃어버려서 그랬어요!","JPN":"あ、あの時はマスクをなくしたから仕方なったんです！","ENG":"I-it's because I lost my mask back then!","TWN":"那、那時候是因為我把口罩弄丟了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"냄새 때문에 아찔해지긴 했지만, 그래도 물지는 않았다고요!","JPN":"匂いのせいで一瞬意識が飛んだけど、噛まずに済んだじゃないですか！","ENG":"The smell made me a little dizzy, but I didn't bite!","TWN":"雖然因為氣味有點暈，但還是沒有咬人啊！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"동물 피 같은 걸론 해소할 수 없는 겁니까?","JPN":"あの衝動は動物の血では解消できないのですか？","ENG":"Can't you satiate yourself with animal blood?","TWN":"用動物的血無法解決嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하, 그야 안되죠. 절 짐승쯤으로 여기는 건가요?","JPN":"当たり前でしょう。私を獣扱いしないでくれますか？","ENG":"*Sigh* Nope. Do you think I'm an animal or something?","TWN":"哈！那當然不行。你是把我當成野獸了嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"인간 피를 노리는 쪽도 짐승인 건 매한가지라 생각합니다만.","JPN":"人間の血を狙っている時点で獣と変わらないと思いますが。","ENG":"You're not less of an animal to be seeking human blood, though.","TWN":"我認為覬覦人類的血液也是野獸。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"따라오시죠. 시니어님 방에 응급용 혈액팩을 비축해둔 게 좀 있습니다.","JPN":"ついてきてください。シニアの部屋に、保存しておいた緊急用の血液パックが少しあります。","ENG":"Follow me. There should be some emergency blood packs stored in the Senior's office.","TWN":"跟我來吧。Senior的房間裡有一些應急用的血袋。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진짜요? 앗싸!","JPN":"本当ですか？　やったー！","ENG":"Really? Awesome!","TWN":"真的嗎？太好了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데, 저 벌 주려고 온 거 아니었어요? 당연히 감옥에 갇힐 줄 알았는데.","JPN":"でも、私を懲らしめるために来たのでは？　牢に放り込まれると思ってたのに。","ENG":"But didn't you come to find and punish me? I thought you were throwing me in jail.","TWN":"可是，你不是來懲罰我的嗎？我還以為肯定會被關進監獄呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당장 그럴 일은 없을 겁니다.","JPN":"すぐにはしません。","ENG":"That won't be happening, at least, not right now.","TWN":"暫時不會有那種事。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진심? 저 그럼 자유에요?","JPN":"本当？　じゃあ私って自由ですか？","ENG":"Seriously? Then, I'm free?","TWN":"認真的嗎？那我自由了？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진실을 캐묻기 위한 잔혹한 고문… 같은 것도 안 당하나요?","JPN":"真実を吐き出させるための残酷な拷問……とかもないですか？","ENG":"I won't be tortured... so I tell you all the truth?","TWN":"我不會……因為要追問真相而遭受殘酷的拷問嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"왜 그 부분에서 아쉬워하는진 모르겠습니다만…","JPN":"なぜ残念そうな顔をするのか理解できませんが……","ENG":"I don't know what you are expecting, but...","TWN":"我不明白你為什麼會對此感到遺憾……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신의 처분은 잠시 유예 됐을 뿐입니다. 당신의 죄를 입증할 주요인물이 실종된 상태니까요.","JPN":"あなたの処分については、決定が少し猶予されただけです。あなたの罪を証明できる主要人物が行方不明なので。","ENG":"Your disposition has only been temporarily postponed. Because the key person who can prove your crime is missing at the moment.","TWN":"而且你的處置只是暫時擱置了。因為能證明你罪行的關鍵人物仍舊處於失蹤狀態。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그리고 관리국에선 실종된 시니어를 찾는데 당신이 도움이 될 것이라 판단했습니다.","JPN":"そして、管理局は行方不明のシニアを探すために、あなたの力が役に立つと判断しました。","ENG":"Also, the Administration has decided that you will be of help in searching for the missing Senior.","TWN":"管理局認為你能幫忙尋找失蹤的Senior。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"오늘처럼 멋대로 사라지지만 않는다면 말이죠.","JPN":"今日みたいに勝手にいなくならない限り、です。","ENG":"Only if you don't randomly disappear like you did today, that is.","TWN":"只要不再像今天這樣隨便消失就好了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네! 잭슨 씨를 찾을 수만 있다면, 저 완전 협조할게요!","JPN":"はい！　ジャクソンさんを見つけるためなら何でも協力します！","ENG":"Okay! If we can find Mr. Jackson, then I'm all in!","TWN":"好的！只要能找到傑森，我會全力配合的！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"어때? 내 작품 <color=#ffd34c>선로전환기</color>에 대한 소감은?","JPN":"どう？　私の作品<color=#ffd34c>線路転換器</color>を見た感想は？","ENG":"So? What do you think about my <color=#ffd34c>Track Switcher</color>?","TWN":"怎麼樣？對我的作品<color=#ffd34c>變軌器</color>有什麼感想？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대단하군.","JPN":"これはすごい。","ENG":"I'm impressed.","TWN":"真是厲害。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"장치를 가동한 것만으로, 다이브 중이던 차원함선을 다른 좌표에 보내다니.","JPN":"装置を稼働しただけで、ダイブ中の次元艦船を別の座標へ送れるとは。","ENG":"I can't believe a dimensional ship that was already diving was sent to a different coordinate just by turning it on.","TWN":"僅僅是啟動裝置，就能將正在躍入的次元艦船送到其他座標。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"단기간에 이 정도 수준의 프로토타입을 만들어내는 건 나로선 엄두도 못 낼 일이야.","JPN":"私としては、短時間でこの程度のプロトタイプを完成するなんて夢のような話だ。","ENG":"Creating a working prototype of this level in such a short amount of time would be unthinkable for me.","TWN":"短時間內能製作出這種水準的原型，我是完全做不到的。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"어…? 그래?","JPN":"え……？　そうなの？","ENG":"Oh...? Really?","TWN":"呃……？是嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 웃기고 있네. 내가 자기보다 낫다고?","JPN":"ふん、冗談でしょう。私があなたよりすごい？","ENG":"Hmph. Don't make me laugh. You think I'm better than you?","TWN":"哼，真是可笑。你說我比你強？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이터니움 드라이브 같은 걸 만들어낸 인간이… 겸손을 떠는 것도 정도가 있지.","JPN":"エタニウムドライブみたいなものを作ったくせに……謙遜しすぎはよくないよ。","ENG":"You made the Eternium Drive... so don't try to appease me.","TWN":"你是製造出永恆之金驅動器的人類……謙虛也要有個限度。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"헤……","JPN":"へへ……","ENG":"Heh...","TWN":"哈……"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래도 놀리는 표정은 아닌 것 같으니까…","JPN":"でも、別にからかってる訳じゃないみたいだし……","ENG":"But since you don't look like you're teasing me...","TWN":"不過看起來並不是在嘲笑我……"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"일단 칭찬 정도로 받아줄까나?","JPN":"純粋に受け入れてやろうかな？","ENG":"Maybe I'll just take it as a compliment.","TWN":"那就先接受你的稱讚吧？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"후… 후후…","JPN":"ふ……ふふ……","ENG":"He... Hehe...","TWN":"嘿……嘿嘿嘿……"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 어려운 일은 아니었어. 당신의 이터니움 드라이브를 참고했을 뿐이니까.","JPN":"難しい作業じゃなかった。あなたのエタニウムドライブを参考にしただけだから。","ENG":"It wasn't that difficult. I just referenced your Eternium Drive.","TWN":"這並不是什麼難事。我只是參考了你的永恆之金驅動器而已。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다음 단계는, 차원함선을 넘어서 마왕을 상대로도 효력을 발휘할 수 있게 전환기의 최대 출력을 높이는 거야.","JPN":"次のステップは、次元艦船を越えて、魔王相手でも力を発揮できるように転換器の最大出力を上げることなの。","ENG":"The next step is to increase the maximum output of the converter so that it can be effective against the Demon Lord too, not just the dimensional ship.","TWN":"下一步是提升轉換器的最大輸出，使其不僅能傳送次元艦船，還能對魔王發揮效力。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"유일한 문제는 마왕이 차원을 뚫고 나가는 힘이 어느 정도인지 알 수 없다는 건데…","JPN":"唯一の問題点は、魔王が次元を通過する力がどれほどのものなのか把握できないってとこだけど……","ENG":"The only problem is that we don't know the amount of power a Demon Lord uses to break through the dimension...","TWN":"唯一的問題是無法知道魔王穿越次元的力量有多強……"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 부분은 내가 참견을 좀 해도 되겠나?","JPN":"そこは私から少し、意見を述べさせてくれないか？","ENG":"May I add to this part?","TWN":"那部分我可以插手一下嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕과 관련된 수치 데이터라면 예전에 측정해둔 게 있거든.","JPN":"魔王関連の数値データなら、以前測定したものがある。","ENG":"I measured data on Demon Lords once in the past.","TWN":"如果是和魔王相關的資料，我以前有測量過。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그거 설마… 내 연구를 돕겠다는 뜻이야?","JPN":"それって……私の研究を手伝うってこと？","ENG":"Are you... saying that you're going to help with my research?","TWN":"那難道是說……你要幫我研究嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런. 내 간섭이 자네 심기를 거스른 건가?","JPN":"おっと。気に障ったのなら謝ろう。","ENG":"Oh. I didn't mean to offend you.","TWN":"呃，是我隨便干涉進來，讓你不高興了嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 아니야. 그럴 리가.","JPN":"う、ううん。まさか。","ENG":"N-no. Not at all.","TWN":"不，不是，怎麼可能。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"협력 좋지. 좋고 말고.","JPN":"協力……いいね。うん。いいよ。","ENG":"I'm fine with your cooperation. Be my guest.","TWN":"合作很好，非常好。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…지금 당장 개발 시작할까?!","JPN":"……今すぐ開発にとりかかろうか！？","ENG":"...Then, shall we get started right away?!","TWN":"……現在馬上開始開發嗎？！"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최고관리자님, 시니어님.","JPN":"最高管理者様、シニア。","ENG":"Supreme Administrator and Senior Isolde.","TWN":"最高管理者、前輩。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"바깥에 손님이 찾아오셨습니다.","JPN":"お客さんが来ています。","ENG":"There is a guest waiting for you both outside.","TWN":"外面有客人來了。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"우리 바쁘니까, 메모만 남기라 하고 일단 돌려보내.","JPN":"私たちは今忙しいの。メモだけもらって帰らせて。","ENG":"We're busy, so tell them to leave a note and go.","TWN":"我們很忙的，有什麼事讓他留下便條，然後離開吧。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠시만 기다려주게.","JPN":"少し待ちたまえ。","ENG":"Hold on.","TWN":"請稍等一下。"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혹시 그 손님의 이름이 뭐라고 하던가?","JPN":"客の名前を教えてくれるか？","ENG":"What was this guest's name?","TWN":"那位客人是叫什麼名字？"},"stage":{"bg":"HANGAR","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"오러 선생님.","JPN":"オーラ先生。","ENG":"Ms. Aura.","TWN":"奧蘿師父。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"저희는 아직 준비도 안됐는데, 이렇게 갑작스럽게 찾아와도 되는 걸까요?","JPN":"準備もまだなのに、突然訪ねてもいいのでしょうか？","ENG":"Are you sure we can come here all of a sudden when we have nothing prepared?","TWN":"我們還沒準備好，這樣突然來訪可以嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"AURA_ADMIN_HELMET_HELMET","text":{"KOREA":"부담 가질 필요 없다!","JPN":"難しく考える必要はない！","ENG":"There's no need to feel pressure!","TWN":"不需要有壓力！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_HELMET_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AURA_ADMIN_HELMET_HELMET","text":{"KOREA":"어제 연락한 펠릭스의 말대로라면, 지금이 우리가 관리국에게 필요한 때니까!","JPN":"昨日フェリックスから聞いた話どおりなら、今こそ管理局には私たちが必要なはず！","ENG":"If what Felix told us yesterday is true, then now is the time the Administration needs us!","TWN":"按照昨天聯絡的緋莉克絲的說法，現在正是管理局需要我們的時候！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_HELMET_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"그치만 전 아직… 경험이 부족한 걸요.","JPN":"でも私は……まだ経験が足りません。","ENG":"But I... still lack experience.","TWN":"可是我還……經驗不足呢。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"역시 좀 더 수련을 하고 찾아오는 편이…","JPN":"やっぱりもうちょっと修行を積んでからにしたほうが……","ENG":"Wouldn't it be better to come back after I train some more...?","TWN":"果然還是多修煉一下再來找他們比較好……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"날 찾았다고 했나?","JPN":"私を探していると聞いたが？","ENG":"I heard you wanted to see me?","TWN":"聽說是有人在找我嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"힛…! 만나버렸다!","JPN":"ひっ……！　会ってしまった！","ENG":"Eep...! It's him!","TWN":"呃……！見到了！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_SERIOUS2"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"아, 안녕하세요?!","JPN":"は、始めまして！？","ENG":"H-hello?!","TWN":"你、你好？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"저는 노르드나빅 키덜링턴 출신, 로빈 피츠워터입니다!!","JPN":"私はノルドナビックのキドリントン出身、ロビン・フィッツウォーターです！！","ENG":"My name is Robin Fitzwater from Kidderlington, Nordnavik!!","TWN":"我是來自諾爾德萊比吉德靈頓的蘿蘋·菲茲瓦特！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…반갑네, 피츠워터 양.","JPN":"……そうか、よろしく頼む。フィッツウォーター君。","ENG":"...Pleased to meet you, Miss Fitzwater.","TWN":"……很高興見到你，菲茲瓦特小姐。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"손님이 한 명이라 들었는데, 두 사람이었군.","JPN":"客は1人だと聞いていたが、2人いたんだな。","ENG":"I heard we had only one guest, but I see that there are two.","TWN":"我以為客人只有一位，原來是兩位啊。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 다시 만나서 반갑네.","JPN":"また会えて嬉しいぞ。","ENG":"It's great to see you again.","TWN":"很高興再次見到你。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오러 전대장.","JPN":"オーラ戦隊長。","ENG":"Commander Aura.","TWN":"奧蘿戰隊長。"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AURA_ADMIN_HELMET_HELMET","text":{"KOREA":"오랜만이다, 관리자!","JPN":"久しぶりだな、管理者！","ENG":"Long time no see, Administrator!","TWN":"好久不見，管理者！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_HELMET_HELMET","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL_06"},{"id":"L48_1","type":"dialog","speaker":"AURA_ADMIN_HELMET_HELMET","text":{"KOREA":"나, 라만차 돌격전대의 오러…!","JPN":"このラマンチャ突撃戦隊のオーラ……！","ENG":"I, Aura of the La Mancha Stormtrooper Division...!","TWN":"我，拉曼查突擊戰隊的奧蘿……！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_HELMET_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AURA_ADMIN_HELMET_HELMET","text":{"KOREA":"관리국과 함께 싸우기 위해 다시 돌아왔다!","JPN":"管理局と共に戦うため、再び帰ってきたぞ！","ENG":"Have returned to fight alongside the Administration!","TWN":"為了與管理局並肩作戰，又回來了！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_HELMET_HELMET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"AURA_ADMIN_ROBIN_HELMET","text":{"KOREA":"아아… 선생님… 결국 선언해버리셨어.","JPN":"ああ……先生……宣言しちゃった。","ENG":"Oh, no... She... just said it.","TWN":"唉唷……師父……你怎麼自己先說啦。"},"stage":{"bg":"SKY","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_ROBIN_HELMET","face":"UNIT_SERIOUS2"},"C":null,"R":null}}}]`);export{e as default};